mapper.select:
SELECT a.*, count(b.id) as categoryCount FROM kol_attribute_type a LEFT JOIN (SELECT * FROM kol_tag_category WHERE parent_id = '0') b ON a.id = b.category_type_id WHERE a.del_flag = 0
and a.type = #{kolAttributeType.type}
and a.type_code = #{kolAttributeType.typeCode}
GROUP BY a.id ORDER BY a.sort_code
